@page "/board"
@using sv_30e8e5a875df4f748b630851d415435c.Components.Pages.Board
@rendermode InteractiveServer
@inject ITaskService TaskService

<PageTitle>Kanban Board</PageTitle>

<h3 class="mb-3">Kanban Board</h3>

@if (loading)
{
    <div class="d-flex justify-content-center my-5">
        <div class="spinner-border" role="status">
            <span class="visually-hidden">Loading...</span>
        </div>
    </div>
}
else if (errorMessage is not null)
{
    <div class="alert alert-danger" role="alert">
        <strong>Error:</strong> @errorMessage
        <button class="btn btn-outline-danger btn-sm ms-3" @onclick="LoadTasks">Retry</button>
    </div>
}
else
{
    <BoardStats Tasks="allTasks" />

    <BoardSearchBar SearchText="@searchText" SearchTextChanged="text => searchText = text" />

    <div class="row g-3">
        @for (var i = 0; i < columns.Length; i++)
        {
            var colIndex = i;
            var col = columns[colIndex];
            var columnTasks = FilteredTasks.Where(t => t.Status == col).ToList();

            <KanbanColumn Title="@col"
                          Status="@col"
                          Tasks="columnTasks"
                          CanMoveLeft="colIndex > 0"
                          CanMoveRight="colIndex < columns.Length - 1"
                          OnMoveLeft="id => MoveTask(id, columns[colIndex - 1])"
                          OnMoveRight="id => MoveTask(id, columns[colIndex + 1])"
                          OnTaskCreated="HandleTaskCreated"
                          TaskService="TaskService" />
        }
    </div>
}

@code {
    private static readonly string[] columns = ["To Do", "In Progress", "Done"];

    private List<TaskItem> allTasks = [];
    private string searchText = string.Empty;
    private bool loading = true;
    private string? errorMessage;

    private List<TaskItem> FilteredTasks =>
        string.IsNullOrWhiteSpace(searchText)
            ? allTasks
            : allTasks.Where(t => t.Title.Contains(searchText, StringComparison.OrdinalIgnoreCase)).ToList();

    protected override async Task OnInitializedAsync()
    {
        await LoadTasks();
    }

    private async Task LoadTasks()
    {
        loading = true;
        errorMessage = null;

        try
        {
            allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
        finally
        {
            loading = false;
        }
    }

    private async Task MoveTask(int taskId, string newStatus)
    {
        try
        {
            await TaskService.UpdateTaskStatusAsync(taskId, newStatus);
            var task = allTasks.First(t => t.Id == taskId);
            allTasks = allTasks.Select(t => t.Id == taskId ? task with { Status = newStatus } : t).ToList();
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
    }

    private void HandleTaskCreated(TaskItem task)
    {
        allTasks.Add(task);
    }
}

